async function callExternalApi(url, { method = "GET", body, apiKey, headers = {} } = {}) {
  const allowedHosts = ["api.example.com", "api.partner.com"];
  const parsedUrl = new URL(url);

  if (!allowedHosts.includes(parsedUrl.hostname)) {
    throw new Error(`Requests to host "${parsedUrl.hostname}" are not allowed`);
  }

  if (!["https:"].includes(parsedUrl.protocol)) {
    throw new Error(`Protocol "${parsedUrl.protocol}" is not allowed`);
  }

  const response = await fetch(parsedUrl.href, {
    method,
    headers: {
      "Authorization": `Bearer ${apiKey}`,
      "Content-Type": "application/json",
      ...headers,
    },
    body: body ? JSON.stringify(body) : undefined,
  });

  if (!response.ok) {
    throw new Error(`API request failed: ${response.status} ${response.statusText}`);
  }

  return response.json();
}

